import React, { Component, Fragment } from 'react';
import { AttributionControl, GeoJSON, Map, TileLayer, ZoomControl } from 'react-leaflet-universal';
import 'leaflet/dist/leaflet.css';
import './map.css';
import { apiGet } from '../apiHelpers';
import { HelpIcon } from '../components/icons';
import Legend from './legend';
import SearchBox from './search-box';
import ThemeSwitcher from './theme-switcher';
const OS_API_KEY = 'NVUxtY5r8eA6eIfwrPTAGKrAAsoeI9E9';
/**
 * Map area
 */
class ColouringMap extends Component {
    constructor(props) {
        super(props);
        this.state = {
            theme: 'night',
            lat: 50.5876,
            lng: 26.2235,
            zoom: 16,
            boundary: undefined,
        };
        this.handleClick = this.handleClick.bind(this);
        this.handleLocate = this.handleLocate.bind(this);
        this.themeSwitch = this.themeSwitch.bind(this);
    }
    handleLocate(lat, lng, zoom) {
        this.setState({
            lat: lat,
            lng: lng,
            zoom: zoom
        });
    }
    handleClick(e) {
        const mode = this.props.mode;
        const { lat, lng } = e.latlng;
        apiGet(`/api/buildings/locate?lat=${lat}&lng=${lng}`)
            .then(data => {
            if (data && data.length) {
                const building = data[0];
                if (mode === 'multi-edit') {
                    // colour building directly
                    this.props.colourBuilding(building);
                }
                else if (this.props.building == undefined || building.building_id !== this.props.building.building_id) {
                    this.props.selectBuilding(building);
                }
                else {
                    this.props.selectBuilding(undefined);
                }
            }
            else {
                if (mode !== 'multi-edit') {
                    // deselect but keep/return to expected colour theme
                    // except if in multi-edit (never select building, only colour on click)
                    this.props.selectBuilding(undefined);
                }
            }
        }).catch((err) => console.error(err));
    }
    themeSwitch(e) {
        e.preventDefault();
        const newTheme = (this.state.theme === 'light') ? 'night' : 'light';
        this.setState({ theme: newTheme });
    }
    async getBoundary() {
        const data = await apiGet('/geometries/boundary-detailed.geojson');
        this.setState({
            boundary: data
        });
    }
    componentDidMount() {
        this.getBoundary();
    }
    render() {
        const position = [this.state.lat, this.state.lng];
        // baselayer
        const key = OS_API_KEY;
        const tilematrixSet = 'EPSG:3857';
        const layer = (this.state.theme === 'light') ? 'Light 3857' : 'Night 3857';
        const baseUrl = `https://api2.ordnancesurvey.co.uk/mapping_api/v1/service/zxy/${tilematrixSet}/${layer}/{z}/{x}/{y}.png?key=${key}`;
        const attribution = 'Building attribute data is © Colouring Bahrain contributors. Maps contain OS data © Crown copyright: OS Maps baselayers and building outlines. <a href=/ordnance-survey-licence.html>OS licence</a>';
        const baseLayer = React.createElement(TileLayer, { url: baseUrl, attribution: attribution, maxNativeZoom: 18, maxZoom: 19 });
        const buildingsBaseUrl = `/tiles/base_${this.state.theme}/{z}/{x}/{y}{r}.png`;
        const buildingBaseLayer = React.createElement(TileLayer, { url: buildingsBaseUrl, minZoom: 14, maxZoom: 19 });
        const boundaryStyleFn = () => ({ color: '#bbb', fill: false });
        const boundaryLayer = this.state.boundary &&
            React.createElement(GeoJSON, { data: this.state.boundary, style: boundaryStyleFn });
        // colour-data tiles
        const cat = this.props.category;
        const tilesetByCat = {
            age: 'date_year',
            size: 'size_height',
            construction: 'construction_core_material',
            location: 'location',
            community: 'likes',
            planning: 'planning_combined',
            sustainability: 'sust_dec',
            type: 'building_attachment_form',
            use: 'landuse'
        };
        const tileset = tilesetByCat[cat];
        // pick revision id to bust browser cache
        const rev = this.props.revision_id;
        const dataLayer = tileset != undefined ?
            React.createElement(TileLayer, { key: tileset, url: `/tiles/${tileset}/{z}/{x}/{y}{r}.png?rev=${rev}`, minZoom: 9, maxZoom: 19 })
            : null;
        // highlight
        const highlightLayer = this.props.building != undefined ?
            React.createElement(TileLayer, { key: this.props.building.building_id, url: `/tiles/highlight/{z}/{x}/{y}{r}.png?highlight=${this.props.building.building_id}&base=${tileset}`, minZoom: 13, maxZoom: 19, zIndex: 100 })
            : null;
        const numbersLayer = React.createElement(TileLayer, { key: this.state.theme, url: `/tiles/number_labels/{z}/{x}/{y}{r}.png?rev=${rev}`, zIndex: 200, minZoom: 17, maxZoom: 19 });
        const isEdit = ['edit', 'multi-edit'].includes(this.props.mode);
        return (React.createElement("div", { className: "map-container" },
            React.createElement(Map, { center: position, zoom: this.state.zoom, minZoom: 9, maxZoom: 19, doubleClickZoom: false, zoomControl: false, attributionControl: false, onClick: this.handleClick, detectRetina: true },
                baseLayer,
                buildingBaseLayer,
                boundaryLayer,
                dataLayer,
                highlightLayer,
                numbersLayer,
                React.createElement(ZoomControl, { position: "topright" }),
                React.createElement(AttributionControl, { prefix: "" })),
            this.props.mode !== 'basic' ? (React.createElement(Fragment, null,
                this.props.building == undefined ?
                    React.createElement("div", { className: "map-notice" },
                        React.createElement(HelpIcon, null),
                        " ",
                        isEdit ? 'Click a building to edit' : 'Click a building for details')
                    : null,
                React.createElement(Legend, { slug: cat }),
                React.createElement(ThemeSwitcher, { onSubmit: this.themeSwitch, currentTheme: this.state.theme }),
                React.createElement(SearchBox, { onLocate: this.handleLocate }))) : null));
    }
}
export default ColouringMap;
